import boto3
from botocore.exceptions import NoCredentialsError, PartialCredentialsError, SSLError
import json

# Create a SQS client using the default configuration file and load environment variables for AWS credentials
sqs = boto3.client('sqs')
queue_url = 'https://sqs.us-east-2.amazonaws.com/123456789012/myQueue'  # replace with your queue url

def handle_message(body):
    """
    Function to process the message body and perform actions based on content
    """
    data = json.loads(body)
    
    if 'actionType' in data:
        action_type = data['actionType']
        
        # Handle different types of messages dynamically here
        if action_type == 'print':
            print('Received message:', data.get('message'))
            
def poll_sqs():
    """
    Function to continuously poll SQS queue for new messages and process them
    """
    while True:
        try:
            # Receive the message from the SQS queue
            response = sqs.receive_message(
                QueueUrl=queue_url,
                MaxNumberOfMessages=10,  # adjust as needed
                WaitTimeSeconds=20  # adjust as needed
            )
            
            if 'Messages' in response:
                for message in response['Messages']:
                    handle_message(message['Body'])
                    
                    # Delete the processed messages from SQS queue to prevent processing duplicates
                    sqs.delete_message(
                        QueueUrl=queue_url,
                        ReceiptHandle=message['ReceiptHandle']
                    )
        except (NoCredentialsError, PartialCredentialsError) as e:
            print('AWS credentials error:', str(e))
        except SSLError as e:
            print('SSL Error:', str(e))
        except Exception as e:  # Catch all other exceptions
            print('Unexpected exception:', str(e))

# Start polling for messages from SQS queue
poll_sqs()